module top_module(input clk, input rst, input data, output reg [2:0] q);reg [2:0] r_reg;

    always @(posedge clk or negedge rst) begin
        if (rst == 0) begin
            r_reg <= 3'b0;
        end
        else begin
            r_reg <= {r_reg[1:0], data};
        end
    end

    assign q = r_reg;
endmodule
